"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth, getOnboardingRoute } from "@/lib/AuthContext";

export default function LoginPage() {
    const { login, isAuthenticated, isLoadingAuth, user } = useAuth();
    const router = useRouter();
    const [tab, setTab] = useState<"login" | "signup">("login");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [displayName, setDisplayName] = useState("");
    const [error, setError] = useState("");
    const [loading, setLoading] = useState(false);

    // Redirect if already authed
    useEffect(() => {
        if (!isLoadingAuth && isAuthenticated && user) {
            const next = getOnboardingRoute(user);
            router.replace(next ?? "/feed");
        }
    }, [isAuthenticated, isLoadingAuth, user, router]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setLoading(true);
        try {
            if (tab === "login") {
                await login(email, password);
                // redirect handled by useEffect above via isAuthenticated change
            } else {
                const res = await fetch("/api/auth/signup", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ email, password, displayName }),
                    credentials: "include",
                });
                const data = await res.json();
                if (!res.ok) throw new Error(data.error ?? "Signup failed");
                // Login after signup
                await login(email, password);
            }
        } catch (err: any) {
            setError(err.message ?? "Something went wrong");
        } finally {
            setLoading(false);
        }
    };

    if (isLoadingAuth) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <div className="w-6 h-6 border-2 border-slate-300 border-t-slate-700 rounded-full animate-spin" />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center p-4">
            <div className="w-full max-w-md">
                {/* Header */}
                <div className="text-center mb-8">
                    <div className="text-5xl mb-3">🦇</div>
                    <h1 className="text-3xl font-black text-white tracking-tight">Campus Echo</h1>
                    <p className="text-slate-400 text-sm mt-1">Anonymous social for students</p>
                </div>

                {/* Card */}
                <div className="bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl p-6 shadow-2xl">
                    {/* Tab switcher */}
                    <div className="flex bg-white/10 p-1 rounded-xl mb-6">
                        {(["login", "signup"] as const).map((t) => (
                            <button
                                key={t}
                                onClick={() => { setTab(t); setError(""); }}
                                className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${tab === t ? "bg-white text-slate-900 shadow" : "text-slate-400 hover:text-white"
                                    }`}
                            >
                                {t === "login" ? "Sign In" : "Sign Up"}
                            </button>
                        ))}
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-4">
                        {tab === "signup" && (
                            <div>
                                <label className="block text-xs font-medium text-slate-300 mb-1.5">Display Name</label>
                                <input
                                    type="text"
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    placeholder="How you'll appear"
                                    className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-slate-500 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50 focus:border-blue-400/50 transition-all"
                                />
                            </div>
                        )}

                        <div>
                            <label className="block text-xs font-medium text-slate-300 mb-1.5">Email</label>
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="you@example.com"
                                required
                                className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-slate-500 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50 focus:border-blue-400/50 transition-all"
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-medium text-slate-300 mb-1.5">Password</label>
                            <input
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder={tab === "signup" ? "Min 8 chars, 1 uppercase, 1 number" : "Your password"}
                                required
                                className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-slate-500 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50 focus:border-blue-400/50 transition-all"
                            />
                        </div>

                        {error && (
                            <div className="bg-red-500/20 border border-red-500/30 rounded-xl px-4 py-3 text-red-300 text-sm">
                                {error}
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full bg-blue-500 hover:bg-blue-400 disabled:opacity-60 disabled:cursor-not-allowed text-white font-bold py-3 rounded-xl transition-all text-sm shadow-lg shadow-blue-500/30 hover:shadow-blue-400/40 active:scale-95"
                        >
                            {loading ? (
                                <span className="flex items-center justify-center gap-2">
                                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                    {tab === "login" ? "Signing in…" : "Creating account…"}
                                </span>
                            ) : tab === "login" ? "Sign In" : "Create Account"}
                        </button>
                    </form>

                    {tab === "signup" && (
                        <p className="text-slate-500 text-xs text-center mt-4">
                            You&apos;ll verify your school email after signing up.
                        </p>
                    )}
                </div>
            </div>
        </div>
    );
}
